import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import FranchiseProcessGuide from './components/FranchiseProcessGuide';
import Login from './components/Login';
import { STEPS } from './constants';
import { User } from './types';

const DEMO_USER: User = { name: 'Demo Franchisee', email: 'demo@creationcoffee.com' };

const App: React.FC = () => {
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());
  const [completedTasks, setCompletedTasks] = useState<Set<string>>(new Set());

  // Initialize with session user or the default demo user to skip login
  const [currentUser, setCurrentUser] = useState<User>(() => {
    const sessionUser = sessionStorage.getItem('currentUser');
    return sessionUser ? JSON.parse(sessionUser) : DEMO_USER;
  });

  useEffect(() => {
    // Load progress for whoever the current user is (Demo or Session)
    loadUserProgress(currentUser.email);
  }, [currentUser.email]);

  const loadUserProgress = (email: string) => {
    const savedSteps = localStorage.getItem(`franchise_progress_steps_${email}`);
    if (savedSteps) {
      setCompletedSteps(new Set(JSON.parse(savedSteps)));
    } else {
      setCompletedSteps(new Set());
    }

    const savedTasks = localStorage.getItem(`franchise_progress_tasks_${email}`);
    if (savedTasks) {
      setCompletedTasks(new Set(JSON.parse(savedTasks)));
    } else {
      setCompletedTasks(new Set());
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    sessionStorage.setItem('currentUser', JSON.stringify(user));
    loadUserProgress(user.email);
  };

  const handleLogout = () => {
    // Instead of null, we revert to demo user or we could show login
    // For "skipping" purpose, let's just clear session and keep demo
    sessionStorage.removeItem('currentUser');
    setCurrentUser(DEMO_USER);
  };

  const handleStepComplete = (stepId: number) => {
    const newCompletedSteps = new Set(completedSteps);
    newCompletedSteps.add(stepId);
    setCompletedSteps(newCompletedSteps);

    // To ensure data consistency, also mark all tasks in this step as complete
    const stepTasks = STEPS.find(s => s.id === stepId)?.tasks.map(t => t.id) || [];
    const newCompletedTasks = new Set([...completedTasks, ...stepTasks]);
    setCompletedTasks(newCompletedTasks);

    // Save progress for the current user
    if (currentUser) {
      localStorage.setItem(`franchise_progress_steps_${currentUser.email}`, JSON.stringify(Array.from(newCompletedSteps)));
      localStorage.setItem(`franchise_progress_tasks_${currentUser.email}`, JSON.stringify(Array.from(newCompletedTasks)));
    }
  };

  const handleTaskToggle = (taskId: string) => {
    const newCompletedTasks = new Set(completedTasks);
    if (newCompletedTasks.has(taskId)) {
      newCompletedTasks.delete(taskId);
    } else {
      newCompletedTasks.add(taskId);
    }
    setCompletedTasks(newCompletedTasks);
    if (currentUser) {
      localStorage.setItem(`franchise_progress_tasks_${currentUser.email}`, JSON.stringify(Array.from(newCompletedTasks)));
    }
  };

  const totalTasks = STEPS.reduce((total, step) => total + step.tasks.length, 0);
  const progress = totalTasks > 0 ? (completedTasks.size / totalTasks) * 100 : 0;

  // Login component is now only accessible if someone explicitly logs out and we chose to show it,
  // but per request we are skipping it, so we always render the main app.
  return (
    <div className="min-h-screen bg-gray-950 font-sans">
      <Header progress={progress} currentUser={currentUser} onLogout={handleLogout} />
      <main className="container mx-auto px-4 py-8">
        <FranchiseProcessGuide 
          completedSteps={completedSteps} 
          onStepComplete={handleStepComplete} 
          completedTasks={completedTasks}
          onTaskToggle={handleTaskToggle}
        />
      </main>
      <footer className="text-center py-6 text-gray-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Creation Coffee Franchising. All rights reserved.</p>
      </footer>
    </div>
  );
};

