import { createClient } from 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';

// These should be set in your environment variables
const supabaseUrl = (window as any).process?.env?.VITE_SUPABASE_URL || '';
const supabaseAnonKey = (window as any).process?.env?.VITE_SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import FranchiseProcessGuide from './components/FranchiseProcessGuide';
import Login from './components/Login';
import { STEPS } from './constants';
import { User } from './types';
import { supabase } from './lib/supabase';

const App: React.FC = () => {
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());
  const [completedTasks, setCompletedTasks] = useState<Set<string>>(new Set());
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check for existing session
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        const user: User = { 
          name: session.user.user_metadata.full_name || 'Franchisee', 
          email: session.user.email || '' 
        };
        setCurrentUser(user);
        loadUserProgress(session.user.id);
      } else {
        setLoading(false);
      }
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        const user: User = { 
          name: session.user.user_metadata.full_name || 'Franchisee', 
          email: session.user.email || '' 
        };
        setCurrentUser(user);
        loadUserProgress(session.user.id);
      } else {
        setCurrentUser(null);
        setCompletedSteps(new Set());
        setCompletedTasks(new Set());
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const loadUserProgress = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('user_progress')
        .select('*')
        .eq('user_id', userId)
        .single();

      if (data) {
        setCompletedSteps(new Set(data.completed_steps));
        setCompletedTasks(new Set(data.completed_tasks));
      }
    } catch (err) {
      console.error('Error loading progress:', err);
    } finally {
      setLoading(false);
    }
  };

  const saveProgress = async (steps: number[], tasks: string[]) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    await supabase
      .from('user_progress')
      .upsert({
        user_id: user.id,
        completed_steps: steps,
        completed_tasks: tasks,
        updated_at: new Date().toISOString()
      });
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleStepComplete = (stepId: number) => {
    const newCompletedSteps = new Set(completedSteps);
    newCompletedSteps.add(stepId);
    setCompletedSteps(newCompletedSteps);

    const stepTasks = STEPS.find(s => s.id === stepId)?.tasks.map(t => t.id) || [];
    const newCompletedTasks = new Set([...completedTasks, ...stepTasks]);
    setCompletedTasks(newCompletedTasks);

    saveProgress(Array.from(newCompletedSteps), Array.from(newCompletedTasks));
  };

  const handleTaskToggle = (taskId: string) => {
    const newCompletedTasks = new Set(completedTasks);
    if (newCompletedTasks.has(taskId)) {
      newCompletedTasks.delete(taskId);
    } else {
      newCompletedTasks.add(taskId);
    }
    setCompletedTasks(newCompletedTasks);
    saveProgress(Array.from(completedSteps), Array.from(newCompletedTasks));
  };

  const totalTasks = STEPS.reduce((total, step) => total + step.tasks.length, 0);
  const progress = totalTasks > 0 ? (completedTasks.size / totalTasks) * 100 : 0;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-amber-600"></div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login />;
  }

  return (
    <div className="min-h-screen bg-gray-950 font-sans">
      <Header progress={progress} currentUser={currentUser} onLogout={handleLogout} />
      <main className="container mx-auto px-4 py-8">
        <FranchiseProcessGuide 
          completedSteps={completedSteps} 
          onStepComplete={handleStepComplete} 
          completedTasks={completedTasks}
          onTaskToggle={handleTaskToggle}
        />
      </main>
      <footer className="text-center py-6 text-gray-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Creation Coffee Franchising. All rights reserved.</p>
      </footer>
    </div>
  );
};

