          </form>

          <p className="mt-6 text-sm text-gray-500">
            {isLoginView ? "Don't have an account?" : 'Already have an account?'}
            <button onClick={toggleView} className="ml-1 font-semibold text-amber-500 hover:text-amber-400 focus:outline-none focus:underline">
