import { createClient } from 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';

/**
 * Safely retrieves environment variables from various possible sources.
 * This handles cases where 'process' might not be defined in the browser 
 * and checks for both standard and Vite-style prefixes.
 */
const getEnv = (key: string): string | undefined => {
  // Check standard process.env (Common in Webpack/CRA)
  try {
    if (typeof process !== 'undefined' && process.env && process.env[key]) {
      return process.env[key];
    }
  } catch (e) {}

  // Check Vite-style import.meta.env
  try {
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env[key]) {
      // @ts-ignore
      return import.meta.env[key];
    }
  } catch (e) {}

  // Check window globals or potential injection points
  const win = window as any;
  if (win.__ENV__ && win.__ENV__[key]) return win.__ENV__[key];
  if (win.process?.env && win.process.env[key]) return win.process.env[key];

  return undefined;
};

// Try both standard and Vite-prefixed keys to ensure compatibility
const supabaseUrl = getEnv('SUPABASE_URL') || getEnv('VITE_SUPABASE_URL');
const supabaseAnonKey = getEnv('SUPABASE_ANON_KEY') || getEnv('VITE_SUPABASE_ANON_KEY');

// We export a boolean to help the UI show a setup guide if keys are missing
export const isSupabaseConfigured = !!(supabaseUrl && supabaseAnonKey);

// Initialize the client. 
// If keys are missing, we use placeholders to avoid a reference error crash, 
// allowing the App.tsx to catch isSupabaseConfigured and show the setup UI.
export const supabase = createClient(
  supabaseUrl || 'https://placeholder-url.supabase.co',
  supabaseAnonKey || 'placeholder-key'
);

