  // Helpful Setup Screen if keys are missing
  if (!isSupabaseConfigured) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-gray-900 border border-gray-800 rounded-2xl p-8 shadow-2xl">
          <div className="flex items-center justify-center h-16 w-16 bg-amber-900/20 border-2 border-amber-600 rounded-full mb-6 mx-auto">
            <span className="text-amber-600 text-4xl font-black">!</span>
          </div>
          <h2 className="text-2xl font-bold text-white text-center mb-4">Configuration Required</h2>
          <p className="text-gray-400 text-center mb-6">
            To make this app functional, you need to connect your Supabase project.
          </p>
          <div className="space-y-4 text-sm">
            <div className="bg-gray-800 p-4 rounded-lg border border-gray-700">
              <p className="text-amber-500 font-bold mb-1">Vercel Deployment:</p>
              <p className="text-gray-300">Add <code>SUPABASE_URL</code> and <code>SUPABASE_ANON_KEY</code> to your Environment Variables in the Vercel dashboard.</p>
            </div>
            <div className="bg-gray-800 p-4 rounded-lg border border-gray-700">
              <p className="text-amber-500 font-bold mb-1">Supabase Setup:</p>
              <p className="text-gray-300">Run the SQL script provided in the previous step to create the <code>user_progress</code> table.</p>
            </div>
          </div>
          <button 
            onClick={() => window.location.reload()}
            className="w-full mt-8 px-8 py-3 bg-amber-600 text-white font-bold rounded-lg hover:bg-amber-500 transition-colors"
          >
            I've Added My Keys, Refresh
          </button>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login />;
  }

  return (
    <div className="min-h-screen bg-gray-950 font-sans">
      <Header progress={progress} currentUser={currentUser} onLogout={handleLogout} />
      <main className="container mx-auto px-4 py-8">
        <FranchiseProcessGuide 
          completedSteps={completedSteps} 
          onStepComplete={handleStepComplete} 
          completedTasks={completedTasks}
          onTaskToggle={handleTaskToggle}
        />
      </main>
      <footer className="text-center py-6 text-gray-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Creation Coffee Franchising. All rights reserved.</p>
      </footer>
    </div>
  );
};

