          </p>
          <div className="space-y-4 text-sm">
            <div className="bg-gray-800 p-4 rounded-lg border border-gray-700">
              <p className="text-amber-500 font-bold mb-1">Vercel Deployment:</p>
              <p className="text-gray-300">Add <code>SUPABASE_URL</code> and <code>SUPABASE_ANON_KEY</code> to your Environment Variables in the Vercel dashboard.</p>
            </div>
            <div className="bg-gray-800 p-4 rounded-lg border border-gray-700">
              <p className="text-amber-500 font-bold mb-1">Supabase Setup:</p>
              <p className="text-gray-300">Run the SQL script provided in the previous step to create the <code>user_progress</code> table.</p>
            </div>
          </div>
          <button 
            onClick={() => window.location.reload()}
            className="w-full mt-8 px-8 py-3 bg-amber-600 text-white font-bold rounded-lg hover:bg-amber-500 transition-colors"
          >
            I've Added My Keys, Refresh
          </button>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login />;
  }

  return (
    <div className="min-h-screen bg-gray-950 font-sans">
      <Header progress={progress} currentUser={currentUser} onLogout={handleLogout} />
      <main className="container mx-auto px-4 py-8">
        <FranchiseProcessGuide 
          completedSteps={completedSteps} 
          onStepComplete={handleStepComplete} 
          completedTasks={completedTasks}
          onTaskToggle={handleTaskToggle}
        />
      </main>
      <AIAssistant 
        currentUser={currentUser} 
        completedTasks={completedTasks} 
        progress={progress} 
      />
      <footer className="text-center py-6 text-gray-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Creation Coffee Franchising. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { STEPS } from '../constants';
import { User } from '../types';

interface AIAssistantProps {
  currentUser: User;
  completedTasks: Set<string>;
  progress: number;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ currentUser, completedTasks, progress }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string }[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsTyping(true);

    try {
      // FIX: Correct initialization using named parameter and direct access to process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Construct context for the AI
      const incompleteTasks = STEPS.flatMap(s => s.tasks)
        .filter(t => !completedTasks.has(t.id))
        .map(t => t.text)
        .slice(0, 5); // Limit to top 5 for prompt efficiency

      const systemInstruction = `
        You are the "Creation Coffee Genie", a helpful AI assistant for new franchisees.
        The user's name is ${currentUser.name}.
        They are currently ${Math.round(progress)}% through the onboarding process.
        Remaining immediate tasks include: ${incompleteTasks.join(', ')}.

        Guidelines:
        1. Be encouraging, professional, and knowledgeable about Creation Coffee's process.
        2. Use the "STEPS" provided in the application context to answer questions.
        3. If they ask about a specific step, refer to the subtitle and description of that step.
        4. Keep responses concise but warm.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
          { role: 'user', parts: [{ text: userMessage }] }
        ],
        config: {
          systemInstruction,
          temperature: 0.7,
        },
      });

      // FIX: Accessing .text property directly (not a method) as per SDK instructions
      const aiText = response.text || "I'm sorry, I'm having a bit of trouble connecting to my coffee beans right now. Could you try again?";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error("Gemini Error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "I encountered an error. Please ensure your API key is configured correctly." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {/* Floating Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-14 h-14 bg-amber-600 hover:bg-amber-500 text-white rounded-full shadow-2xl flex items-center justify-center transition-all hover:scale-110 active:scale-95 group"
      >
        {isOpen ? (
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        ) : (
          <div className="relative">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
            </svg>
            <span className="absolute -top-1 -right-1 flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
            </span>
          </div>
        )}
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="absolute bottom-16 right-0 w-[350px] sm:w-[400px] h-[500px] bg-gray-900 border border-gray-800 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="p-4 bg-gray-800 border-b border-gray-700 flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-amber-600 rounded-full flex items-center justify-center font-bold text-white text-sm">C</div>
              <div>
                <h3 className="text-white font-bold text-sm">Creation Genie</h3>
                <p className="text-xs text-green-400">Online • AI Onboarding Guide</p>
              </div>
            </div>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-950/50">
            {messages.length === 0 && (
              <div className="text-center py-8">
                <div className="w-12 h-12 bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-3">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                </div>
                <p className="text-gray-400 text-sm px-6 italic">
                  "Hi {currentUser.name}! I can help you with FDD questions, buildout steps, or just tell you what's next in your journey."
                </p>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                  m.role === 'user' 
                    ? 'bg-amber-600 text-white rounded-tr-none' 
                    : 'bg-gray-800 text-gray-200 rounded-tl-none border border-gray-700'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-gray-800 p-3 rounded-2xl rounded-tl-none border border-gray-700">
                  <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                    <div className="w-1.5 h-1.5 bg-gray-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                  </div>
                </div>
              </div>
            )}
          </div>

          <form onSubmit={handleSendMessage} className="p-4 bg-gray-900 border-t border-gray-800">
            <div className="relative">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask me anything..."
                className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-sm focus:outline-none focus:ring-2 focus:ring-amber-500 pr-12 transition-all"
              />
              <button
                type="submit"
                disabled={!input.trim() || isTyping}
                className="absolute right-2 top-1.5 p-1.5 bg-amber-600 text-white rounded-lg hover:bg-amber-500 disabled:opacity-50 disabled:hover:bg-amber-600 transition-colors"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                </svg>
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import FranchiseProcessGuide from './components/FranchiseProcessGuide';
import Login from './components/Login';
import AIAssistant from './components/AIAssistant';
import { STEPS } from './constants';
import { User } from './types';
import { supabase, isSupabaseConfigured } from './lib/supabase';

const App: React.FC = () => {
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());
  const [completedTasks, setCompletedTasks] = useState<Set<string>>(new Set());
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    // Check for existing session
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        const user: User = { 
          name: session.user.user_metadata.full_name || 'Franchisee', 
          email: session.user.email || '' 
        };
        setCurrentUser(user);
        loadUserProgress(session.user.id);
      } else {
        setLoading(false);
      }
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        const user: User = { 
          name: session.user.user_metadata.full_name || 'Franchisee', 
          email: session.user.email || '' 
        };
        setCurrentUser(user);
        loadUserProgress(session.user.id);
      } else {
        setCurrentUser(null);
        setCompletedSteps(new Set());
        setCompletedTasks(new Set());
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const loadUserProgress = async (userId: string) => {
    try {
      const { data } = await supabase
        .from('user_progress')
        .select('*')
        .eq('user_id', userId)
        .single();

      if (data) {
        setCompletedSteps(new Set(data.completed_steps as number[]));
        setCompletedTasks(new Set(data.completed_tasks as string[]));
      }
    } catch (err) {
      console.error('Error loading progress:', err);
    } finally {
      setLoading(false);
    }
  };

  const saveProgress = async (steps: number[], tasks: string[]) => {
    if (!isSupabaseConfigured) return;
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    await supabase
      .from('user_progress')
      .upsert({
        user_id: user.id,
        completed_steps: steps,
        completed_tasks: tasks,
        updated_at: new Date().toISOString()
      });
  };

  const handleLogout = async () => {
    if (isSupabaseConfigured) {
      await supabase.auth.signOut();
    }
  };

  const handleStepComplete = (stepId: number) => {
    const newCompletedSteps = new Set<number>(completedSteps);
    newCompletedSteps.add(stepId);
    setCompletedSteps(newCompletedSteps);

    const stepTasks = STEPS.find(s => s.id === stepId)?.tasks.map(t => t.id) || [];
    const newCompletedTasks = new Set<string>([...Array.from(completedTasks), ...stepTasks]);
    setCompletedTasks(newCompletedTasks);
    saveProgress(Array.from(newCompletedSteps), Array.from(newCompletedTasks));
  };

  const handleTaskToggle = (taskId: string) => {
    const newCompletedTasks = new Set<string>(completedTasks);
    if (newCompletedTasks.has(taskId)) {
      newCompletedTasks.delete(taskId);
    } else {
      newCompletedTasks.add(taskId);
    }
    setCompletedTasks(newCompletedTasks);
    saveProgress(Array.from(completedSteps), Array.from(newCompletedTasks));
  };

  const totalTasks = STEPS.reduce((total, step) => total + step.tasks.length, 0);
  const progress = totalTasks > 0 ? (completedTasks.size / totalTasks) * 100 : 0;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-amber-600"></div>
      </div>
    );
  }

  // Enhanced Configuration Screen
  if (!isSupabaseConfigured) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-gray-900 border border-gray-800 rounded-2xl p-8 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-amber-600"></div>

          <div className="flex items-center justify-center h-16 w-16 bg-amber-900/20 border-2 border-amber-600 rounded-full mb-6 mx-auto">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>

          <h2 className="text-2xl font-bold text-white text-center mb-2">Connect Your Backend</h2>
          <p className="text-gray-400 text-center mb-8">
            Your app is ready, but it needs to talk to Supabase to save franchisee progress.
          </p>

          <div className="space-y-4">
            <div className="bg-gray-800/50 p-4 rounded-xl border border-gray-700">
              <div className="flex items-center mb-2">
                <span className="w-6 h-6 rounded-full bg-amber-600 text-white text-xs flex items-center justify-center font-bold mr-2">1</span>
                <p className="text-white font-semibold">Open Editor Sidebar</p>
              </div>
              <p className="text-sm text-gray-400 pl-8">Look for the <span className="text-amber-500 font-mono">Secrets</span> tab or a <span className="text-amber-500 font-mono">Lock (🔒)</span> icon in the left-hand sidebar of this builder.</p>
            </div>

            <div className="bg-gray-800/50 p-4 rounded-xl border border-gray-700">
              <div className="flex items-center mb-2">
                <span className="w-6 h-6 rounded-full bg-amber-600 text-white text-xs flex items-center justify-center font-bold mr-2">2</span>
                <p className="text-white font-semibold">Add Your Keys</p>
              </div>
              <div className="pl-8 space-y-2">
                <div className="flex items-center justify-between text-xs bg-gray-950 p-2 rounded border border-gray-800">
                  <code className="text-amber-400">SUPABASE_URL</code>
                  <span className="text-gray-600">Paste URL</span>
                </div>
                <div className="flex items-center justify-between text-xs bg-gray-950 p-2 rounded border border-gray-800">
                  <code className="text-amber-400">SUPABASE_ANON_KEY</code>
                  <span className="text-gray-600">Paste Key</span>
                </div>
              </div>
            </div>
          </div>

          <button 
            onClick={() => window.location.reload()}
            className="w-full mt-8 px-8 py-3 bg-amber-600 text-white font-bold rounded-xl hover:bg-amber-500 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
          >
            I've Added My Keys, Reload App
          </button>

          <p className="mt-4 text-[10px] text-gray-500 text-center uppercase tracking-widest">
            Ensure you run the SQL script in Supabase first
          </p>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login />;
  }

  return (
    <div className="min-h-screen bg-gray-950 font-sans">
      <Header progress={progress} currentUser={currentUser} onLogout={handleLogout} />
      <main className="container mx-auto px-4 py-8">
        <FranchiseProcessGuide 
          completedSteps={completedSteps} 
          onStepComplete={handleStepComplete} 
          completedTasks={completedTasks}
          onTaskToggle={handleTaskToggle}
        />
      </main>
      <AIAssistant 
        currentUser={currentUser} 
        completedTasks={completedTasks} 
        progress={progress} 
      />
      <footer className="text-center py-6 text-gray-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Creation Coffee Franchising. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;
